import { Injectable } from '@nestjs/common';

import { StyleColorModel } from '@modules/db/style-colors/models/style-color.model';
import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
import { IStyleColorCreate } from '@modules/db/style-colors/types/style-color.create.interface';

@Injectable()
export class StyleColorsService {
	constructor(private readonly styleColorModel: StyleColorModel) {}

	async storeStyle({
		data,
	}: {
		data: Partial<IStyleColorCreate> & {
			style_id: IStyleColorBase['style_id'];
			color_id: IStyleColorBase['color_id'];
		};
	}): Promise<IStyleColorBase> {
		return await this.styleColorModel.upsertStyle({ data });
	}

	async getStyleByStyleAndColorId({
		styleId,
		colorId,
	}: {
		styleId: IStyleColorBase['style_id'];
		colorId: number;
	}): Promise<IStyleColorBase | null> {
		return this.styleColorModel.findByStyleAndColorId({ styleId, colorId });
	}

	async getStyleByStyleId({
		styleId,
	}: {
		styleId: IStyleColorBase['style_id'];
	}): Promise<IStyleColorBase | null> {
		return this.styleColorModel.findByStyleId({ styleId });
	}

	async getStyleByColorId({
		colorId,
	}: {
		colorId: number;
	}): Promise<IStyleColorBase | null> {
		return this.styleColorModel.findByColorId({ colorId });
	}

	async deleteStyle({
		styleId,
		colorId,
	}: {
		styleId: IStyleColorBase['style_id'];
		colorId: number;
	}): Promise<void> {
		await this.styleColorModel.softDelete({ styleId, colorId });
	}
}

