import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { instanceToPlain, plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { BaseStyleColorDto } from '@modules/db/style-colors/dto/style-color.base.dto';
import { CreateStyleColorDto } from '@modules/db/style-colors/dto/style-color.create.dto';
import { UpdateStyleColorDto } from '@modules/db/style-colors/dto/style-color.update.dto';
import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
import { IStyleColorCreate } from '@modules/db/style-colors/types/style-color.create.interface';
import { IStyleColorUpdate } from '@modules/db/style-colors/types/style-color.update.interface';

import {
	KNEX_READ_CONNECTION,
	KNEX_WRITE_CONNECTION,
	TABLE_NAME_STYLES_COLORS,
} from '@constants/db.constant';

@Injectable()
export class StyleColorModel {
	private readonly logger = new Logger(StyleColorModel.name);
	private readonly tableName = TABLE_NAME_STYLES_COLORS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async create({ data }: { data: IStyleColorCreate }): Promise<IStyleColorBase> {
		const _id = randomUUID();

		const styleData: IStyleColorCreate & { _id: IStyleColorBase['_id'] } = {
			...data,
			_id,
		};

		const dto = plainToInstance(CreateStyleColorDto, styleData);
		const errors = await validate(dto);

		if (errors.length > 0) {
			this.logger.error(
				`Validation failed for style data: ${this.formatValidationErrors({ errors })}`,
			);
			throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
		}

		try {
			const res = await this.knexWrite.transaction(async (trx) => {
				await trx(this.tableName).insert(styleData);

				return await trx<BaseStyleColorDto>(this.tableName)
					.where({
						style_id: data.style_id,
						color_id: data.color_id,
					})
					.whereNull('deleted_at')
					.orderBy('created_at', 'desc')
					.first();
			});

			if (!res) {
				this.logger.error(`Failed to insert style with ID ${_id}`);
				throw new Error(`Failed to insert style with ID ${_id}`);
			}

			this.logger.debug(`Inserted style with ID ${_id}`);

			return this.parseStyleColorData({
				data: instanceToPlain<BaseStyleColorDto>(res) as IStyleColorBase,
			});
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(`Failed to create style: ${err.message}`);
			throw err;
		}
	}

	async findByStyleId({
		styleId,
	}: {
		styleId: IStyleColorBase['style_id'];
