		};
	}): Promise<IStyleColorBase> {
		try {
			const upsertedStyle: IStyleColorBase = await this.knexWrite.transaction(
				async (trx) => {
					const existing = await trx<IStyleColorBase>(this.tableName)
						.where({ style_id: data.style_id, color_id: data.color_id })
						.whereNull('deleted_at')
						.first();

					if (existing) {
						const updateData: Record<string, unknown> = {
							updated_at: trx.fn.now(),
						};

						if ('color_rgb' in data) {
							updateData['color_rgb'] = data.color_rgb;
						}
						if ('color_name' in data) {
							updateData['color_name'] = data.color_name;
						}
						if ('is_active' in data) {
							updateData['is_active'] = data.is_active;
						}

						if ('image_url' in data) {
							updateData['image_url'] = data.image_url;
						}

						await trx(this.tableName)
							.where({ style_id: data.style_id, color_id: data.color_id })
							.update(updateData);
					} else {
						const _id = randomUUID();
						const insertData: IStyleColorCreate & { _id: IStyleColorBase['_id'] } = {
							_id,
							style_id: data.style_id,
							color_id: data.color_id,
							color_rgb: data.color_rgb ?? null,
							color_name: data.color_name ?? '',
							is_active: data.is_active ?? true,
							image_url: data.image_url ?? null,
						};

						const dto = plainToInstance(CreateStyleColorDto, insertData);
						const errors = await validate(dto);

						if (errors.length > 0) {
							this.logger.error(
								`Validation failed for style color data: ${this.formatValidationErrors({ errors })}`,
							);
							throw new Error(
								`Validation failed: ${this.formatValidationErrors({ errors })}`,
							);
						}

						await trx(this.tableName).insert(insertData);
					}

					const result = await trx<IStyleColorBase>(this.tableName)
						.where({
							style_id: data.style_id,
							color_id: data.color_id,
						})
						.whereNull('deleted_at')
						.first();

					if (!result) {
						throw new Error(
							`Failed to upsert style with style ID ${data.style_id} and color ID ${data.color_id}`,
						);
					}

					return result;
				},
			);

			this.logger.debug(
				`Upserted style for styleId ${data.style_id} and colorId ${data.color_id}`,
			);

			const styleDto = new BaseStyleColorDto();
			Object.assign(styleDto, upsertedStyle);
			return this.parseStyleColorData({
				data: instanceToPlain<BaseStyleColorDto>(styleDto) as IStyleColorBase,
			});
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(
				`Failed to upsert style with style ID ${data.style_id} and color ID ${data.color_id}: ${err.message}`,
			);
			throw err;
		}
	}

