import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { instanceToPlain, plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import {
	BaseTrendingProductsDto,
	CreateTrendingProductsDto,
} from '@modules/db/forecasted-trending-products/dto/forecasted-trending-products.base.dto';
import {
	ITrendingProductsBase,
	ITrendingProductsCreate,
} from '@modules/db/forecasted-trending-products/types/forecasted-trending-products.base.interface';

import {
	KNEX_READ_CONNECTION,
	KNEX_WRITE_CONNECTION,
	TABLE_NAME_TRENDING_PRODUCTS,
	TABLE_NAME_STYLES,
	TABLE_NAME_STYLE_CATEGORIES,
} from '@constants/db.constant';

@Injectable()
export class ForecastedTrendingProductsModel {
	private readonly logger = new Logger(ForecastedTrendingProductsModel.name);

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async invalidateLatestForecasts(): Promise<void> {
		await this.knexWrite(TABLE_NAME_TRENDING_PRODUCTS)
			.update({ is_latest: 0, updated_at: this.knexWrite.fn.now() })
			.where('is_latest', 1);
	}

	async deactivateOldPredictions(): Promise<void> {
		await this.knexWrite(TABLE_NAME_TRENDING_PRODUCTS)
			.update({ is_active: 0, updated_at: this.knexWrite.fn.now() })
			.where('is_active', 1);
	}

	async activateLatestPredictions(): Promise<void> {
		await this.knexWrite.transaction(async (trx) => {
			await trx(TABLE_NAME_TRENDING_PRODUCTS).update({
				is_active: 0,
				updated_at: trx.fn.now(),
			});

			await trx(TABLE_NAME_TRENDING_PRODUCTS)
				.update({ is_active: 1, updated_at: trx.fn.now() })
				.where('is_latest', 1);
		});
	}

	async getTrendingProductsByCategory({
		categoryId,
		excludeProductIds,
		limit = 10,
		offset = 0,
	}: {
		categoryId: number;
		excludeProductIds?: number[];
		limit?: number;
		offset?: number;
	}): Promise<ITrendingProductsBase[]> {
		return await this.knexRead.transaction(async (trx) => {
			const minProducts = 5;
			let allResults: ITrendingProductsBase[] = [];
			let excludedIds = excludeProductIds ?? [];

			const firstQuery = trx<ITrendingProductsBase>(TABLE_NAME_TRENDING_PRODUCTS)
				.select(`${TABLE_NAME_TRENDING_PRODUCTS}.*`)
				.join(
					TABLE_NAME_STYLES,
					`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`,
					`${TABLE_NAME_STYLES}.style_id`,
				)
				.join(TABLE_NAME_STYLE_CATEGORIES, (join) => {
					join
						.on(
							`${TABLE_NAME_STYLE_CATEGORIES}.style_id`,
							`${TABLE_NAME_STYLES}.style_id`,
						)
						.andOnVal(`${TABLE_NAME_STYLE_CATEGORIES}.category_id`, categoryId);
				})
				.andWhere(`${TABLE_NAME_TRENDING_PRODUCTS}.is_active`, 1)
				.whereNull(`${TABLE_NAME_STYLES}.deleted_at`)
				.where(`${TABLE_NAME_TRENDING_PRODUCTS}.total_predicted_orders`, '>=', 10)
				.orderBy(`${TABLE_NAME_TRENDING_PRODUCTS}.trend_score`, 'desc');

			if (excludedIds.length > 0) {
				firstQuery.whereNotIn(`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`, excludedIds);
			}

			if (limit) {
				firstQuery.limit(limit);
			}

			if (offset) {
				firstQuery.offset(offset);
			}

			const firstResults = await firstQuery;
			allResults = await this.validateResults({ results: firstResults });

			this.logger.debug(`First query returned ${allResults.length} products`);

			if (allResults.length < minProducts) {
				excludedIds = [
					...excludedIds,
					...allResults.map((result) => Number(result.style_id)),
				];

				const fallbackQuery = trx<ITrendingProductsBase>(TABLE_NAME_TRENDING_PRODUCTS)
					.select(`${TABLE_NAME_TRENDING_PRODUCTS}.*`)
					.join(
						TABLE_NAME_STYLES,
						`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`,
						`${TABLE_NAME_STYLES}.style_id`,
					)
					.join(TABLE_NAME_STYLE_CATEGORIES, (join) => {
						join
							.on(
								`${TABLE_NAME_STYLE_CATEGORIES}.style_id`,
								`${TABLE_NAME_STYLES}.style_id`,
							)
							.andOnVal(`${TABLE_NAME_STYLE_CATEGORIES}.category_id`, categoryId);
					})
					.andWhere(`${TABLE_NAME_TRENDING_PRODUCTS}.is_active`, 1)
					.whereNull(`${TABLE_NAME_STYLES}.deleted_at`)
					.whereNotIn(`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`, excludedIds)
					.orderBy(`${TABLE_NAME_TRENDING_PRODUCTS}.trend_score`, 'desc')
					.limit(minProducts - allResults.length);

				const fallbackResults = await fallbackQuery;
				const validatedFallbackResults = await this.validateResults({
					results: fallbackResults,
				});

				allResults = allResults.concat(validatedFallbackResults);

				this.logger.debug(
					`Fallback query returned ${validatedFallbackResults.length} additional products`,
				);
			}

			this.logger.debug(`Total products returned: ${allResults.length}`);
			return allResults;
		});
	}

	async getTrendingProductsByCategories({
		categoryIds,
		excludeProductIds,
		limit = 100,
		offset = 0,
	}: {
		categoryIds: number[];
		excludeProductIds?: number[];
		limit?: number;
		offset?: number;
	}): Promise<ITrendingProductsBase[]> {
		const query = this.knexRead<ITrendingProductsBase>(TABLE_NAME_TRENDING_PRODUCTS)
			.select(`${TABLE_NAME_TRENDING_PRODUCTS}.*`)
			.join(
				TABLE_NAME_STYLES,
				`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`,
				`${TABLE_NAME_STYLES}.style_id`,
			)
			.whereIn(
				`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`,
				this.knexRead(TABLE_NAME_STYLE_CATEGORIES)
					.select('style_id')
					.whereIn('category_id', categoryIds),
			)
			.andWhere(`${TABLE_NAME_TRENDING_PRODUCTS}.is_active`, 1)
			.whereNull(`${TABLE_NAME_STYLES}.deleted_at`)
			.where(`${TABLE_NAME_TRENDING_PRODUCTS}.total_predicted_orders`, '>=', 10)
			.orderBy(`${TABLE_NAME_TRENDING_PRODUCTS}.trend_score`, 'desc')
			.limit(limit)
			.offset(offset);

		if (excludeProductIds && excludeProductIds.length > 0) {
			query.whereNotIn(`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`, excludeProductIds);
		}

		const results = await query;
		return this.validateResults({ results });
	}

	async getTrendingProductsByCategoryAndStyleIds({
		categoryId,
		styleIds,
		limit = 100,
		offset = 0,
	}: {
		categoryId: number;
		styleIds: number[];
		limit?: number;
		offset?: number;
	}): Promise<ITrendingProductsBase[]> {
		const query = this.knexRead<ITrendingProductsBase>(TABLE_NAME_TRENDING_PRODUCTS)
			.select(`${TABLE_NAME_TRENDING_PRODUCTS}.*`)
			.join(
				TABLE_NAME_STYLES,
				`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`,
				`${TABLE_NAME_STYLES}.style_id`,
			)
			.join(TABLE_NAME_STYLE_CATEGORIES, (join) => {
				join
					.on(`${TABLE_NAME_STYLE_CATEGORIES}.style_id`, `${TABLE_NAME_STYLES}.style_id`)
					.andOnVal(`${TABLE_NAME_STYLE_CATEGORIES}.category_id`, categoryId);
			})
			.andWhere(`${TABLE_NAME_TRENDING_PRODUCTS}.is_active`, 1)
			.whereNull(`${TABLE_NAME_STYLES}.deleted_at`)
			.whereIn(`${TABLE_NAME_TRENDING_PRODUCTS}.style_id`, styleIds)
			.orderBy(`${TABLE_NAME_TRENDING_PRODUCTS}.trend_score`, 'desc')
			.limit(limit)
			.offset(offset);

		const results = await query;
		return this.validateResults({ results });
	}

	async saveBatchPredictions({
		predictions,
	}: {
		predictions: ITrendingProductsCreate[];
	}): Promise<ITrendingProductsBase[]> {
		return await this.knexWrite.transaction(async (trx) => {
			try {
				this.logger.log('Updated all existing records to set is_latest = false');

				const validationResults = await Promise.all(
					predictions.map(async (prediction) => {
						const styleIdNum = Number(prediction.style_id);
						if (
							String(prediction.style_id) === 'null' ||
							!Number.isInteger(styleIdNum) ||
							styleIdNum <= 0 ||
							Number.isNaN(styleIdNum)
						) {
							return {
								prediction,
								errors: ['invalid_style_id'],
								isManuallyInvalid: true,
							};
						}

						const dto = plainToInstance(CreateTrendingProductsDto, {
							style_id: String(prediction.style_id),
							predicted_orders: prediction.predicted_orders,
							total_predicted_orders: prediction.total_predicted_orders,
							trend_score: prediction.trend_score,
							trending_reason: prediction.trending_reason,
							forecast_start_date: prediction.forecast_start_date,
							forecast_end_date: prediction.forecast_end_date,
							forecast_days: prediction.forecast_days,
						});
						const errors = await validate(dto);
						return { prediction, errors, isManuallyInvalid: false };
					}),
				);

				const validationState = { hasDtoFailures: false };
				const validatedPredictions = validationResults
					.filter(({ prediction, errors, isManuallyInvalid }) => {
						if (isManuallyInvalid) {
							this.logger.warn(
								`Filtered out prediction with invalid style_id: ${prediction.style_id}`,
							);
							return false;
						}
						if (errors.length > 0) {
							this.logger.warn(
								`Validation failed for prediction with style_id ${prediction.style_id}: ${this.formatValidationErrors({ errors: errors as ValidationError[] })}`,
							);
							validationState.hasDtoFailures = true;
							return false;
						}
						return true;
					})
					.map(({ prediction }) => prediction);

				const invalidCount = predictions.length - validatedPredictions.length;
				if (validatedPredictions.length === 0) {
					this.logger.warn(
						validationState.hasDtoFailures
							? 'No valid predictions after validation'
							: 'No valid predictions to save after filtering',
					);
					return [];
				}

				if (invalidCount > 0) {
					this.logger.warn(
						validationState.hasDtoFailures
							? `Filtered out ${invalidCount} predictions during validation`
							: `Filtered out ${invalidCount} invalid predictions`,
					);
				}

				const insertData = validatedPredictions.map((prediction) => ({
					_id: randomUUID(),
					style_id: Number(prediction.style_id),
					is_latest: 1,
					is_active: 0,
					predicted_orders: JSON.stringify(prediction.predicted_orders),
					total_predicted_orders: prediction.total_predicted_orders,
					trend_score: prediction.trend_score,
					trending_reason: prediction.trending_reason,
					forecast_start_date: prediction.forecast_start_date,
					forecast_end_date: prediction.forecast_end_date,
					forecast_days: prediction.forecast_days,
					created_at: trx.fn.now(),
					updated_at: trx.fn.now(),
				}));

				await trx(TABLE_NAME_TRENDING_PRODUCTS).insert(insertData);

				const results = await trx<BaseTrendingProductsDto>(TABLE_NAME_TRENDING_PRODUCTS)
					.whereIn(
						'_id',
						insertData.map((item) => item._id),
					)
					.orderBy('created_at', 'desc');

				const validatedResults = await Promise.all(
					results.map(async (result) => {
						const dto = plainToInstance(BaseTrendingProductsDto, result);
						const errors = await validate(dto);
						if (errors.length > 0) {
							this.logger.error(
								`Validation failed for trending products data: ${this.formatValidationErrors({ errors })}`,
							);
							throw new Error(
								`Validation failed: ${this.formatValidationErrors({ errors })}`,
							);
						}
						return instanceToPlain<BaseTrendingProductsDto>(dto) as ITrendingProductsBase;
					}),
				);

				this.logger.log(
					`Transaction completed successfully. Saved ${validatedResults.length} predictions`,
				);
				return validatedResults;
			} catch (error) {
				this.logger.error(
					`Failed to save batch predictions: ${(error as Error).message}`,
				);
				throw error;
			}
		});
	}

	async getLatestPredictions({
		limit,
		offset = 0,
	}: {
		limit?: number;
		offset?: number;
	} = {}): Promise<ITrendingProductsBase[]> {
		try {
			let query = this.knexRead<BaseTrendingProductsDto>(TABLE_NAME_TRENDING_PRODUCTS)
				.where('is_active', true)
				.orderBy('trend_score', 'desc')
				.orderBy('created_at', 'desc');

			if (limit) {
				query = query.limit(limit);
			}

			if (offset > 0) {
				query = query.offset(offset);
			}

			const results = await query;

			if (results.length === 0) {
				this.logger.debug('No latest predictions found');
				return [];
			}

			const validatedResults = await Promise.all(
				results.map(async (result) => {
					const dto = plainToInstance(BaseTrendingProductsDto, result);
					const errors = await validate(dto);
					if (errors.length > 0) {
						this.logger.error(
							`Validation failed for trending products data: ${this.formatValidationErrors({ errors })}`,
						);
						throw new Error(
							`Validation failed: ${this.formatValidationErrors({ errors })}`,
						);
					}
					return instanceToPlain<BaseTrendingProductsDto>(dto) as ITrendingProductsBase;
				}),
			);

			this.logger.debug(`Found ${validatedResults.length} latest predictions`);
			return validatedResults;
		} catch (error) {
			this.logger.error(`Failed to get latest predictions: ${(error as Error).message}`);
			throw error;
		}
	}

	async getPredictionsByStyleId({
		styleId,
	}: {
		styleId: string;
	}): Promise<ITrendingProductsBase[]> {
		try {
			let query = this.knexRead<BaseTrendingProductsDto>(
				TABLE_NAME_TRENDING_PRODUCTS,
			).where('style_id', styleId);

			query = query.where('is_active', true);

			const results = await query.orderBy('created_at', 'desc');

			if (results.length === 0) {
				this.logger.debug(`No predictions found for style_id ${styleId}`);
				return [];
			}

			const validatedResults = await Promise.all(
				results.map(async (result) => {
					const dto = plainToInstance(BaseTrendingProductsDto, result);
					const errors = await validate(dto);
					if (errors.length > 0) {
						this.logger.error(
							`Validation failed for trending products data: ${this.formatValidationErrors({ errors })}`,
						);
						throw new Error(
							`Validation failed: ${this.formatValidationErrors({ errors })}`,
						);
					}
					return instanceToPlain<BaseTrendingProductsDto>(dto) as ITrendingProductsBase;
				}),
			);

			this.logger.debug(
				`Found ${validatedResults.length} predictions for style_id ${styleId}`,
			);
			return validatedResults;
		} catch (error) {
			this.logger.error(
				`Failed to get predictions for style_id ${styleId}: ${(error as Error).message}`,
			);
			throw error;
		}
